+                if (referent != null) {
+                    int row = WB.isObjectInOldGen(weakRef) ? OLD : YOUNG;
+                    int column = WB.isObjectInOldGen(referent) ? OLD : YOUNG;
+                    getReferences(row, column).add(weakRef);
+                }
+            }
+        }
